#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int C = 0;
        int* D = (int*)malloc(2 * N * N * sizeof(int));
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (A[i] > A[j]) {
                    int temp = A[i];
                    A[i] = A[j];
                    A[j] = temp;
                    D[C] = i + 1;
                    C++;
                }
            }
        }
        printf("%d\n", C);
        for (int i = 0; i < C; i++) {
            printf("%d ", D[i]);
        }
        printf("\n");
        free(A);
        free(D);
    }
    return 0;
}

