import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int C = 0;
            int[] D = new int[2 * N * N];
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    if (A[i] > A[j]) {
                        int temp = A[i];
                        A[i] = A[j];
                        A[j] = temp;
                        D[C] = i + 1;
                        C++;
                    }
                }
            }
            System.out.println(C);
            for (int i = 0; i < C; i++) {
                System.out.print(D[i] + " ");
            }
            System.out.println();
        }
    }
}

