const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const A = readline().split(' ').map(Number);
    let C = 0;
    const D = new Array(2 * N * N).fill(0);
    for (let j = 0; j < N; j++) {
        for (let k = j + 1; k < N; k++) {
            if (A[j] > A[k]) {
                [A[j], A[k]] = [A[k], A[j]];
                D[C] = j + 1;
                C++;
            }
        }
    }
    console.log(C);
    for (let j = 0; j < C; j++) {
        process.stdout.write(D[j] + ' ');
    }
    console.log();
}

